// Normalize Clay payload to Task 4 allow-listed contract only.
const payload = $json.body ?? $json;
const clean = (value) => (value === undefined || value === null ? '' : String(value).trim());

const firstName = clean(payload.first_name || payload['First Name']);
const lastName = clean(payload.last_name || payload['Last Name']);
const contactName =
  clean(payload.contact_name || payload.name || payload['Full Name']) ||
  [firstName, lastName].filter(Boolean).join(' ');

const email = clean(
  payload.email || payload.contact_email || payload.Email || payload['Work Email'],
).toLowerCase();

const fitRaw = payload.fit_score ?? payload['Fit Score'];
const fitScore = typeof fitRaw === 'number' ? fitRaw : Number.parseInt(String(fitRaw ?? ''), 10);

const batchId =
  clean(payload.batch_id) ||
  (() => {
    const fmt = new Intl.DateTimeFormat('en-CA', {
      timeZone: 'America/New_York',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    });
    return `clay-${fmt.format(new Date())}`;
  })();

const row = {
  clay_row_id: clean(payload.clay_row_id || payload.row_id || payload.id),
  batch_id: batchId,
  company_name: clean(payload.company_name || payload.company || payload.Company || payload['Company Name']),
  website: clean(payload.website || payload.domain || payload['Company Domain']),
  contact_name: contactName,
  title: clean(payload.title || payload.contact_title || payload['Job Title']),
  email,
  location: clean(payload.location || payload.city || payload['Company Location']),
  fit_score: Number.isFinite(fitScore) ? fitScore : fitRaw,
  fit_reason: clean(payload.fit_reason || payload['Fit Reason']),
  recommended_service: clean(payload.recommended_service || payload['Recommended Service']),
};

if (!row.clay_row_id) throw new Error('Clay row rejected: clay_row_id is required');
if (!row.company_name) throw new Error('Clay row rejected: company_name is required');
if (!row.website) throw new Error('Clay row rejected: website is required');
if (!row.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(row.email)) {
  throw new Error('Clay row rejected: a valid email is required');
}
if (!row.fit_reason) throw new Error('Clay row rejected: fit_reason is required');
if (!row.recommended_service) throw new Error('Clay row rejected: recommended_service is required');

return [{ json: row }];
